'use client';

import { Plus, Edit, Trash2, GripVertical } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

const faqs = [
  { id: 1, question: 'What is the typical timeline?', order: 1 },
  { id: 2, question: 'How much do services cost?', order: 2 },
];

export default function AdminFAQs() {
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-[#111827]">FAQs</h1>
          <p className="text-gray-500 mt-1">Manage frequently asked questions.</p>
        </div>
        <Button variant="gold" className="rounded-full">
          <Plus className="w-4 h-4 mr-2" />
          Add FAQ
        </Button>
      </div>

      <Card>
        <CardContent className="p-0">
          {faqs.map((faq) => (
            <div key={faq.id} className="flex items-center gap-4 p-4 border-b border-gray-100 hover:bg-gray-50 transition-colors">
              <GripVertical className="w-5 h-5 text-gray-300 cursor-move" />
              <div className="flex-1">
                <h3 className="font-medium text-[#111827]">{faq.question}</h3>
                <p className="text-xs text-gray-500">Order: {faq.order}</p>
              </div>
              <div className="flex gap-2">
                <button className="p-2 hover:bg-gray-100 rounded-lg"><Edit className="w-4 h-4 text-gray-500" /></button>
                <button className="p-2 hover:bg-red-50 rounded-lg"><Trash2 className="w-4 h-4 text-red-500" /></button>
              </div>
            </div>
          ))}
        </CardContent>
      </Card>
    </div>
  );
}

