  if (allowEditor && (session.user.role === 'admin' || session.user.role === 'editor')) return true;
  return session.user.role === 'admin';
}

export async function GET(request: NextRequest) {
  const session = await auth();
  if (!checkAccess(session, true)) {
    return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
  }

  try {
    await connectDB();
  } catch {
    return NextResponse.json({ success: false, error: 'Database connection failed' }, { status: 500 });
  }

  const { searchParams } = new URL(request.url);
  const category = searchParams.get('category') || '';
  const section = searchParams.get('section') || '';
  const search = searchParams.get('search') || '';
  const page = parseInt(searchParams.get('page') || '1');
  const limit = parseInt(searchParams.get('limit') || '20');
  const skip = (page - 1) * limit;

  const filter: Record<string, unknown> = {};
  if (category && category !== 'all') filter.category = category;
  if (section && section !== 'all') filter.section = section;
  if (search) filter.title = { $regex: search, $options: 'i' };

  try {
    const [images, total] = await Promise.all([
      WebsiteImage.find(filter).sort({ createdAt: -1 }).skip(skip).limit(limit).lean(),
      WebsiteImage.countDocuments(filter),
    ]);

    return NextResponse.json({
      success: true,
      images: JSON.parse(JSON.stringify(images)),
      pagination: { page, limit, total, pages: Math.ceil(total / limit) },
    });
  } catch {
    return NextResponse.json({ success: false, error: 'Failed to fetch images' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  const session = await auth();
  if (!checkAccess(session, true)) {
    return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
  }

  try {
    await connectDB();
  } catch {
    return NextResponse.json({ success: false, error: 'Database connection failed' }, { status: 500 });
  }

  try {
    const formData = await request.formData();
    const title = formData.get('title') as string;
    const category = formData.get('category') as string;
    const section = formData.get('section') as string;
    const altText = (formData.get('altText') as string) || '';
    const displayOrder = parseInt(formData.get('displayOrder') as string) || 0;
    const isActive = formData.get('isActive') === 'true';
    const file = formData.get('file') as File | null;

    const parsed = imageSchema.safeParse({ title, category, section, altText, displayOrder, isActive });
    if (!parsed.success) {
      return NextResponse.json({ success: false, error: parsed.error.issues[0].message }, { status: 400 });
    }

    if (!file || file.size === 0) {
      return NextResponse.json({ success: false, error: 'File is required' }, { status: 400 });
    }

    const allowedTypes = ['image/jpeg', 'image/png', 'image/webp', 'image/jpg'];
    if (!allowedTypes.includes(file.type)) {
      return NextResponse.json({ success: false, error: 'Only JPG, PNG, WebP allowed' }, { status: 400 });
    }
    if (file.size > 5 * 1024 * 1024) {
      return NextResponse.json({ success: false, error: 'File too large (max 5MB)' }, { status: 400 });
    }

    const buffer = Buffer.from(await file.arrayBuffer());
    const result = await saveImage(buffer, file.name, parsed.data.category);

    const image = new WebsiteImage({
      title: parsed.data.title,
      category: parsed.data.category,
      section: parsed.data.section,
      altText: parsed.data.altText || '',
      imageUrl: result.imageUrl,
      thumbnailUrl: result.thumbnailUrl,
      imageType: result.imageType,
      fileSize: result.fileSize,
      dimensions: result.dimensions,
      displayOrder: parsed.data.displayOrder,
      isActive: parsed.data.isActive,
      isBranding: parsed.data.category === 'branding',
      uploadedBy: session!.user?.email,
    });

    await image.save();
    revalidatePath('/admin/images');
    revalidatePath('/');
    revalidatePath('/(site)/');
    return NextResponse.json({ success: true, image: JSON.parse(JSON.stringify(image)) });
  } catch {
    return NextResponse.json({ success: false, error: 'Failed to upload image' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { revalidatePath } from 'next/cache';

export async function POST(request: Request) {
  try {
    const { path } = await request.json();

    if (path) {
      revalidatePath(path);
    }

    return NextResponse.json({ success: true, revalidated: true });
  } catch (error) {
    return NextResponse.json({ success: false, error: 'Failed to revalidate' }, { status: 500 });
  }
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X, Moon, Sun, Diamond } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useTheme } from '@/components/ui/theme-provider';
import { cn } from '@/lib/utils/cn';
import { getSettings } from '@/lib/actions/data';

export default function Header() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileOpen, setIsMobileOpen] = useState(false);
  const [navLinks, setNavLinks] = useState<{ label: string; href: string }[]>([]);
  const [ctaText, setCtaText] = useState('Get Free Quote');
  const [ctaLink, setCtaLink] = useState('/contact');
  const [siteName, setSiteName] = useState('AkInteriors');
  const [logo, setLogo] = useState('');
  const pathname = usePathname();
  const { theme, toggleTheme } = useTheme();

  useEffect(() => {
    getSettings().then((settings) => {
      if (settings.nav?.links) setNavLinks(settings.nav.links);
      if (settings.nav?.ctaText) setCtaText(settings.nav.ctaText);
      if (settings.nav?.ctaLink) setCtaLink(settings.nav.ctaLink);
      if (settings.siteName) setSiteName(settings.siteName);
      if (settings.logo) setLogo(settings.logo);
    }).catch(() => {});
  }, []);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // mobile menu closes via Link click handlers instead

  const isHome = pathname === '/';

  return (
    <header
      className={cn(
        'fixed top-0 left-0 right-0 z-50 transition-all duration-500',
        isScrolled
          ? 'bg-white/80 backdrop-blur-xl shadow-sm border-b border-gray-100/50'
          : isHome
          ? 'bg-transparent'
          : 'bg-white/80 backdrop-blur-xl shadow-sm'
      )}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          <Link href="/" className="flex items-center gap-2 group">
            {logo ? (
              <img src={logo} alt={siteName} className="h-8 w-auto" />
            ) : (
              <Diamond className="w-6 h-6 text-[#C8A97E] group-hover:rotate-180 transition-transform duration-500" />
            )}
            <span className={cn(
              'text-2xl font-bold tracking-tight transition-colors',
              isScrolled || !isHome ? 'text-[#111827]' : 'text-white'
            )}>
              {siteName.split(' ')[0] || 'Ak'}
              {siteName.includes(' ') ? <span className="text-[#C8A97E]">{siteName.split(' ').slice(1).join(' ')}</span> : <span className="text-[#C8A97E]">Interiors</span>}
            </span>
          </Link>

          <nav className="hidden lg:flex items-center gap-8">
            {(navLinks.length > 0 ? navLinks : [
              { label: 'Home', href: '/' },
              { label: 'Projects', href: '/projects' },
              { label: 'Services', href: '/services' },
              { label: 'About', href: '/about' },
              { label: 'Contact', href: '/contact' },
            ]).map((link) => (
              <Link
                key={link.href}
                href={link.href}
                className={cn(
                  'relative text-sm font-medium tracking-wide transition-colors duration-300 hover:text-[#C8A97E]',
                  pathname === link.href
                    ? 'text-[#C8A97E]'
                    : isScrolled || !isHome
                    ? 'text-gray-700'
                    : 'text-white/90'
                )}
              >
                {link.label}
                {pathname === link.href && (
                  <motion.span
                    layoutId="underline"
                    className="absolute -bottom-1 left-0 right-0 h-0.5 bg-[#C8A97E]"
                  />
                )}
              </Link>
            ))}
          </nav>

          <div className="flex items-center gap-4">
            <button
              onClick={toggleTheme}
              className={cn(
                'p-2 rounded-full transition-colors',
                isScrolled || !isHome ? 'text-gray-700 hover:bg-gray-100' : 'text-white/90 hover:bg-white/10'
              )}
              aria-label="Toggle theme"
            >
              {theme === 'light' ? <Moon className="w-5 h-5" /> : <Sun className="w-5 h-5" />}
            </button>

            <Link href={ctaLink} className="hidden lg:block">
              <Button variant="gold" size="sm" className="rounded-full">
                {ctaText}
              </Button>
            </Link>

            <button
              onClick={() => setIsMobileOpen(!isMobileOpen)}
              className={cn(
                'lg:hidden p-2 rounded-full transition-colors',
                isScrolled || !isHome ? 'text-gray-700' : 'text-white'
              )}
            >
              {isMobileOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
            </button>
          </div>
        </div>
      </div>

      <AnimatePresence>
        {isMobileOpen && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="lg:hidden bg-white/95 backdrop-blur-xl border-t border-gray-100"
          >
            <div className="px-4 py-6 space-y-4">
              {(navLinks.length > 0 ? navLinks : [
                { label: 'Home', href: '/' },
                { label: 'Projects', href: '/projects' },
                { label: 'Services', href: '/services' },
                { label: 'About', href: '/about' },
                { label: 'Contact', href: '/contact' },
              ]).map((link) => (
                <Link
                  key={link.href}
                  href={link.href}
                  className={cn(
                    'block py-3 text-base font-medium transition-colors',
                    pathname === link.href
                      ? 'text-[#C8A97E]'
                      : 'text-gray-700 hover:text-[#C8A97E]'
                  )}
                >
                  {link.label}
                </Link>
              ))}
              <Link href={ctaLink} className="block">
                <Button variant="gold" className="w-full rounded-full">
                  {ctaText}
                </Button>
              </Link>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </header>
  );
}

